import React from 'react';
import { Input } from '@linm-soft/common-components';
import { COMPANY_FIELD_LABEL } from '../../utils/companyField';
import styles from '../../styles/erpPage.module.css';

export interface CatalogCompanyFieldProps {
  testIdPrefix: string;
  /**
   * Company display label from BE response (`item.companyName`).
   * For create form: derive `sessionCompanyName = items[0]?.companyName`.
   * Never call useCompanyLabelMap() — BE joins and returns this field.
   */
  companyName?: string;
}

/** Display-only đơn vị cơ sở on catalog modal (Create/Edit: disabled xám — EDIT_DISABLED_GRAY).
 * View: bọc `.viewReadOnlySection` — CSS giữ màu active (catalog-list-form-view-readonly.md).
 * companyName comes from BE (joined from PlatformCompanies) — pass `item.companyName`. */
export const CatalogCompanyField: React.FC<CatalogCompanyFieldProps> = ({
  testIdPrefix,
  companyName,
}) => (
  <div className={styles.catalogCompanyFieldRow} data-testid={`${testIdPrefix}-field-companyId-row`}>
    <div className={styles.field} data-testid={`${testIdPrefix}-field-companyId`}>
      <label className={styles.label}>{COMPANY_FIELD_LABEL}</label>
      <Input value={companyName ?? '—'} disabled />
    </div>
  </div>
);
